def set_default_style(document):
    style = document.styles["Normal"]
    style.font.name = "Times New Roman"
    style._element.rPr.rFonts.set(qn("w:eastAsia"), "Times New Roman")
    style.font.size = Pt(14)
    for section in document.sections:
        section.top_margin = Mm(20)
        section.bottom_margin = Mm(20)
        section.left_margin = Mm(30)
        section.right_margin = Mm(15)

def set_paragraph_format(paragraph, align=WD_ALIGN_PARAGRAPH.JUSTIFY, first_line=True):
    paragraph.paragraph_format.line_spacing = 1.5
    paragraph.paragraph_format.space_before = Pt(0)
    paragraph.paragraph_format.space_after = Pt(0)
    paragraph.paragraph_format.first_line_indent = Cm(1.25) if first_line else Cm(0)
    paragraph.alignment = align

def add_run(paragraph, text, bold=False, size=14):
    run = paragraph.add_run(text)
    run.bold = bold
    run.font.name = "Times New Roman"
    run._element.rPr.rFonts.set(qn("w:eastAsia"), "Times New Roman")
    run.font.size = Pt(size)
    return run

def add_text(document, text, align=WD_ALIGN_PARAGRAPH.JUSTIFY, bold=False, first_line=True, size=14):
    paragraph = document.add_paragraph()
    set_paragraph_format(paragraph, align=align, first_line=first_line)
    for idx, part in enumerate(text.split("\n")):
        if idx:
            paragraph.add_run().add_break()
        add_run(paragraph, part, bold=bold, size=size)
    return paragraph

def add_heading(document, text):
    paragraph = document.add_paragraph()
    set_paragraph_format(paragraph, align=WD_ALIGN_PARAGRAPH.CENTER, first_line=False)
    paragraph.paragraph_format.space_before = Pt(24)
    paragraph.paragraph_format.space_after = Pt(12)
    add_run(paragraph, text, bold=True)
    return paragraph

def add_page_number(paragraph):
    run = paragraph.add_run()
    begin = OxmlElement("w:fldChar")
    begin.set(qn("w:fldCharType"), "begin")
    instr = OxmlElement("w:instrText")
    instr.set(qn("xml:space"), "preserve")
    instr.text = "PAGE"
    end = OxmlElement("w:fldChar")
    end.set(qn("w:fldCharType"), "end")
    run._r.append(begin)
    run._r.append(instr)
    run._r.append(end)

def add_toc(paragraph):
    run = paragraph.add_run()
    begin = OxmlElement("w:fldChar")
    begin.set(qn("w:fldCharType"), "begin")
    instr = OxmlElement("w:instrText")
    instr.set(qn("xml:space"), "preserve")
    instr.text = r'TOC \\o "1-3" \\h \\z \\u'
    sep = OxmlElement("w:fldChar")
    sep.set(qn("w:fldCharType"), "separate")
    text = OxmlElement("w:t")
    text.text = "Содержание будет сформировано после обновления полей в Microsoft Word."
    sep.append(text)
    end = OxmlElement("w:fldChar")
    end.set(qn("w:fldCharType"), "end")
    run._r.append(begin)
    run._r.append(instr)
    run._r.append(sep)
    run._r.append(end)
def title_page(document, diary=False):
    for line in TITLE_INFO_LINES:
        add_text(document, line, align=WD_ALIGN_PARAGRAPH.CENTER, first_line=False)
    for _ in range(5):
        add_text(document, "", align=WD_ALIGN_PARAGRAPH.CENTER, first_line=False)
    title = (
        "ДНЕВНИК\nпрохождения производственной практики\n(по профилю специальности)\nпо профессиональному модулю ПМ.02 «Осуществление интеграции программных модулей»"
        if diary
        else "ОТЧЕТ\nпо производственной практике (по профилю специальности)\nпо профессиональному модулю ПМ.02 «Осуществление интеграции программных модулей»"
    )
    add_text(document, title, align=WD_ALIGN_PARAGRAPH.CENTER, bold=True, first_line=False)
    for _ in range(4):
        add_text(document, "", align=WD_ALIGN_PARAGRAPH.CENTER, first_line=False)
    add_text(document, "Специальность 09.02.07 «Информационные системы и программирование»", align=WD_ALIGN_PARAGRAPH.LEFT, first_line=False)
    add_text(document, "Студент(ка) IV курса 22290907/109 группы ________________________________", align=WD_ALIGN_PARAGRAPH.LEFT, first_line=False)
    add_text(document, "Место прохождения практики: ________________________________________________", align=WD_ALIGN_PARAGRAPH.LEFT, first_line=False)
    add_text(document, "Период прохождения практики: с «12» января 2026 г. по «13» февраля 2026 г.", align=WD_ALIGN_PARAGRAPH.LEFT, first_line=False)
    if diary:
        add_text(document, "Руководитель с места прохождения практики: _________________________________", align=WD_ALIGN_PARAGRAPH.LEFT, first_line=False)
    else:
        add_text(document, "Руководитель практики от учебной организации: Зернова Е.Н. __________________\nРуководитель с места прохождения практики: _________________________________\nИтоговая оценка по практике: ________________________________________________", align=WD_ALIGN_PARAGRAPH.LEFT, first_line=False)
    for _ in range(8 if diary else 6):
        add_text(document, "", align=WD_ALIGN_PARAGRAPH.CENTER, first_line=False)
    add_text(document, "Санкт-Петербург", align=WD_ALIGN_PARAGRAPH.CENTER, first_line=False)
    add_text(document, "2026", align=WD_ALIGN_PARAGRAPH.CENTER, first_line=False)

def build_numbered_list(document, items):
    for index, item in enumerate(items, start=1):
        add_text(document, f"{index}. {item}")

def build_diary_table(document):
    add_heading(document, "СОДЕРЖАНИЕ ДНЕВНИКА")
    table = document.add_table(rows=1, cols=3)
    table.style = "Table Grid"
    table.alignment = WD_TABLE_ALIGNMENT.CENTER
    widths = [Cm(2.2), Cm(13.6), Cm(3.1)]
    headers = ["Дата", "Виды выполненных работ и заданий по программе практики", "Подпись руководителя практики"]
    for idx, header in enumerate(headers):
        cell = table.rows[0].cells[idx]
        cell.width = widths[idx]
        cell.vertical_alignment = WD_CELL_VERTICAL_ALIGNMENT.CENTER
        p = cell.paragraphs[0]
        set_paragraph_format(p, align=WD_ALIGN_PARAGRAPH.CENTER, first_line=False)
        add_run(p, header, bold=True, size=12)
    for date, text in DIARY_ENTRIES:
        row = table.add_row()
        values = [date, text, ""]
        aligns = [WD_ALIGN_PARAGRAPH.CENTER, WD_ALIGN_PARAGRAPH.JUSTIFY, WD_ALIGN_PARAGRAPH.CENTER]
        for idx, value in enumerate(values):
            cell = row.cells[idx]
            cell.width = widths[idx]
            cell.vertical_alignment = WD_CELL_VERTICAL_ALIGNMENT.CENTER
            p = cell.paragraphs[0]
            set_paragraph_format(p, align=aligns[idx], first_line=False)
            add_run(p, value, size=12)

def build_document(output_path=OUTPUT_PATH):
    document = Document()
    set_default_style(document)
    document.sections[0].different_first_page_header_footer = True

    title_page(document, diary=False)
    document.add_page_break()
    add_heading(document, "??????????")
    toc_paragraph = document.add_paragraph()
    set_paragraph_format(toc_paragraph, align=WD_ALIGN_PARAGRAPH.LEFT, first_line=False)
    add_toc(toc_paragraph)

    for title, paragraphs in REPORT_SECTIONS:
        document.add_page_break()
        add_heading(document, title)
        for paragraph in paragraphs:
            add_text(document, paragraph)

    document.add_page_break()
    add_heading(document, "?????????????? ????????")
    for paragraph in CHARACTERISTIC:
        add_text(document, paragraph)

    document.add_page_break()
    add_heading(document, "????? ?? ????????")
    for paragraph in PRACTICE_CONCLUSION:
        add_text(document, paragraph)

